+import { Recur } from './Recur.ts';
+
+/**
+ * Replaces every recursive placeholder in a schema graph with its wrapper.
+ */
+export function resolveRecur<TValue>(value: TValue, replacement: unknown): TValue {
+  const resolved = new WeakMap<object, unknown>();
+
+  function resolve<TItem>(item: TItem): TItem {
+    if (item === Recur) {
+      return replacement as TItem;
+    }
+    if (!item || typeof item !== 'object') {
+      return item;
+    }
+    const existing = resolved.get(item);
+    if (existing) {
+      return existing as TItem;
+    }
+
+    const copy = Array.isArray(item)
+      ? []
+      : Object.create(Object.getPrototypeOf(item));
+    resolved.set(item, copy);
+    for (const key of Reflect.ownKeys(item)) {
+      const descriptor = Object.getOwnPropertyDescriptor(item, key);
+      if (descriptor && 'value' in descriptor) {
+        descriptor.value = resolve(descriptor.value);
+      }
+      Object.defineProperty(copy, key, descriptor!);
+    }
+    return copy;
+  }
+
+  return resolve(value);
